INSERT INTO DCS D
(   D.ITEM_DATE            
,	D.REPORT_ID            
,	D.TRANSACTION          
,	D.ORDINARY             
,	D.CHEQUE               
,	D.AO_CAEO              
,	D.INSATIS              
,	D.PTO_ORDER            
,	D.MISCELLANEOUS        
,	D.INOUT                
,	D.USER_ID              
,	D.JGMT1000             
,	D.ADMIN_COURT_CODE      
,	D.ORDINARY_CURRENCY     
,	D.CHEQUE_CURRENCY       
,	D.JGMT1000_CURRENCY     
,	D.AO_CAEO_CURRENCY      
,	D.INSATIS_CURRENCY      
,	D.PTO_ORDER_CURRENCY    
,	D.MISCELLANEOUS_CURRENCY
) VALUES 
(    TO_DATE(${param.itemDate}, 'YYYY-MM-DD')
,    ${param.reportId}
,    ${param.totalNumberOfTransactions}
,    ${param.totalOrdinary}
,    ${param.totalCheque}
,    ${param.totalAOCAEO}
,    ${param.totalInsat}
,    ${param.totalPTO}
,    ${param.totalMiscellaneous}
,    'O'
,    ${param.userId}
,    ${param.totalJGMT1000}
,    ${param.adminCourtCode}
,    'GBP'
,    'GBP'
,    'GBP'
,    'GBP'
,    'GBP'
,    'GBP'
,    'GBP'
)
